import { useState, useEffect } from "react";

const RTG_RED = "#C8102E";
const INK = "#1A1A1A";
const BG = "#FAFAF8";
const WARM = "#F0EBE3";
const RULE = "#E2E2E2";
const SUCCESS = "#1A6B3C";
const SUCCESS_BG = "#E8F5EE";

const PRODUCTS = {
  "RTG-001": {
    id: "RTG-001",
    name: "Cindy Crawford Bellingham Sectional",
    price: 1299,
    emoji: "🛋️",
    category: "Living Room",
    colors: ["Charcoal", "Ivory", "Slate Blue"],
    inStock: true,
    complements: ["RTG-003", "RTG-004"],
  },
  "RTG-002": {
    id: "RTG-002",
    name: "Platform Bed Frame — King",
    price: 849,
    emoji: "🛏️",
    category: "Bedroom",
    colors: ["Espresso", "White", "Grey"],
    inStock: true,
    complements: ["RTG-005", "RTG-006"],
  },
  "RTG-003": {
    id: "RTG-003",
    name: "Lexington Coffee Table",
    price: 349,
    emoji: "🪵",
    category: "Living Room",
    colors: ["Walnut", "Black"],
    inStock: true,
    complements: ["RTG-001"],
  },
  "RTG-004": {
    id: "RTG-004",
    name: "Accent Armchair",
    price: 399,
    emoji: "🪑",
    category: "Living Room",
    colors: ["Cream", "Forest Green", "Terracotta"],
    inStock: false,
    complements: ["RTG-001"],
  },
  "RTG-005": {
    id: "RTG-005",
    name: "6-Drawer Dresser",
    price: 499,
