// ─── Screen 3: Scanner ────────────────────────────────────────────────────────
function ScannerScreen({ onBack, onScanned, scanIndex }) {
  const [scanning, setScanning] = useState(false);
  const [found, setFound] = useState(false);

  const handleScan = () => {
    setScanning(true);
    setTimeout(() => {
      setFound(true);
      setTimeout(() => {
        const productId = SCAN_SEQUENCE[scanIndex % SCAN_SEQUENCE.length];
        onScanned(productId);
      }, 600);
    }, 1800);
  };

  return (
    <div style={{ ...s.screen, background: "#111" }}>
      <div
        style={{
          ...s.header,
          background: "#111",
          borderBottom: "1px solid #333",
        }}
      >
        <button style={{ ...s.backBtn, color: "#fff" }} onClick={onBack}>←</button>
        <span style={{ ...s.headerTitle, color: "#fff" }}>Scan Tag</span>
      </div>

      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 24 }}>
        {/* Viewfinder */}
        <div
          style={{
            width: "100%",
            maxWidth: 300,
            aspectRatio: "1",
            position: "relative",
            marginBottom: 32,
          }}
        >
          <div style={{ position: "absolute", inset: 0, background: "#222", borderRadius: 16, overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center" }}>
            {found ? (
              <div style={{ fontSize: 60, animation: "pulse 0.3s ease" }}>✅</div>
            ) : (
              <div style={{ ...s.mono, fontSize: 12, color: "#555", textAlign: "center" }}>
                {scanning ? "Reading tag..." : "Point at QR code"}
              </div>
            )}
          </div>

          {/* Corners */}
          {["tl", "tr", "bl", "br"].map((pos) => (
            <div
              key={pos}
              style={{
                position: "absolute",
                width: 32,
                height: 32,
                ...(pos === "tl" ? { top: 8, left: 8, borderTop: `3px solid ${RTG_RED}`, borderLeft: `3px solid ${RTG_RED}` } : {}),
                ...(pos === "tr" ? { top: 8, right: 8, borderTop: `3px solid ${RTG_RED}`, borderRight: `3px solid ${RTG_RED}` } : {}),
                ...(pos === "bl" ? { bottom: 8, left: 8, borderBottom: `3px solid ${RTG_RED}`, borderLeft: `3px solid ${RTG_RED}` } : {}),
                ...(pos === "br" ? { bottom: 8, right: 8, borderBottom: `3px solid ${RTG_RED}`, borderRight: `3px solid ${RTG_RED}` } : {}),
              }}
            />
          ))}

          {/* Scan line */}
          {scanning && !found && (
            <div
              style={{
                position: "absolute",
                left: "10%",
                right: "10%",
                height: 2,
                background: RTG_RED,
                boxShadow: `0 0 8px ${RTG_RED}`,
                animation: "scanline 1.2s ease-in-out infinite",
              }}
            />
          )}
        </div>

        {!scanning && !found && (
          <button
            style={{ ...s.btn, maxWidth: 280, borderRadius: 12 }}
            onClick={handleScan}
          >
            📷 &nbsp; Tap to Scan
          </button>
        )}

        {scanning && !found && (
          <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 14, textAlign: "center" }}>
            Scanning...
          </div>
        )}

        <div style={{ color: "#555", fontSize: 12, marginTop: 20, textAlign: "center", lineHeight: 1.6 }}>
          Hold the camera steady over the<br />Quick Response code on the product tag
        </div>
      </div>

      <style>{`
        @keyframes scanline {
          0% { top: 15%; }
          50% { top: 80%; }
          100% { top: 15%; }
        }
      `}</style>
    </div>
  );
}

